### Example 1: Printing an HTTP Request Body (Conceptual)

This example shows how you would *send* an HTTP request and then print the body of the *response*. **It does not print the request content itself, as that is usually handled by the client library.**

```go
package main

import (
	"fmt"
	"io"
	"net/http"
)

func main() {
	url := "https://jsonplaceholder.typicode.com/posts/1"

	fmt.Printf("Attempting to fetch data from: %s\n", url)

	// 1. Create a client
	client := http.Client{}

	// 2. Create the request
	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		fmt.Println("Error creating request:", err)
		return
	}

	// 3. Execute the request
	resp, err := client.Do(req)
	if err != nil {
		fmt.Println("Error executing request:", err)
		return
	}
	defer resp.Body.Close()

	// 4. Read and print the response body content
	fmt.Printf("\n--- Response Status: %s ---\n", resp.Status)
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Error reading response body:", err)
		return
	}
	fmt.Println("Response Body Content:")
	fmt.Println(string(bodyBytes))
}
```

